+#[derive(Debug, Clone, PartialEq, Eq)]
+pub enum ProviderAdapterError<E> {
+    /// No Cx was available from the provider.
+    NoCx(NoCxAvailable),
+    /// The inner service returned an error.
+    Service(E),
+}
+
+#[cfg(feature = "tower")]
